// Lấy toàn bộ item input
const items = $input.all();

// Gom các mention-tag
const mentions = items
  .map(item => item.json.seatalk_id)
  .filter(id => id)
  .map(
    id => `<mention-tag target=\\\"seatalk://user?id=${id}\\\"/>`
  );

// Ghép thành 1 chuỗi xuống dòng (SeaTalk parse tốt nhất)
const content = mentions.join(' - ');

// Trả ra 1 item
return [
  {
    json: {
      content,
    },
  },
];

